# Valid PostgreSQL extension name pattern: lowercase letters, digits, underscores, hyphens
VALID_EXTENSION_NAME_PATTERN = re.compile(r'^[a-z][a-z0-9_\-]{0,62}$')


def validate_extension_name(extension_name: str) -> str:
    """
    Validate and sanitize an extension name to prevent SQL injection.
    
    - Strips whitespace
    - Checks against allowlist
    - Validates character pattern
    - Returns the validated name or raises ValueError
    """
    if not extension_name or not isinstance(extension_name, str):
        raise ValueError("Extension name must be a non-empty string.")
    
    cleaned_name = extension_name.strip().lower()
    
    if not cleaned_name:
        raise ValueError("Extension name cannot be empty or whitespace only.")
    
    # Check against valid pattern to prevent any injection attempts
    if not VALID_EXTENSION_NAME_PATTERN.match(cleaned_name):
        raise ValueError(
            f"Invalid extension name format: '{cleaned_name}'. "
            "Extension names must start with a lowercase letter and contain only "
            "lowercase letters, digits, underscores, or hyphens (max 63 chars)."
        )
    
    # Check against allowlist
    if cleaned_name not in ALLOWED_EXTENSIONS:
        raise ValueError(
            f"Extension '{cleaned_name}' is not in the list of allowed extensions. "
            f"Allowed extensions: {', '.join(sorted(ALLOWED_EXTENSIONS))}"
        )
    
    return cleaned_name


def install_extension(connection, extension_name: str, if_not_exists: bool = True) -> bool:
    """
    Safely install a PostgreSQL extension.
    
    Uses allowlist validation and psycopg2's sql module for safe identifier quoting
    to prevent SQL injection attacks.
    
    Args:
        connection: psycopg2 connection object
        extension_name: Name of the extension to install
        if_not_exists: If True, use IF NOT EXISTS clause
        
    Returns:
        True if the extension was installed successfully
        
    Raises:
        ValueError: If the extension name is invalid or not allowed
        psycopg2.Error: If there's a database error
    """
    # Validate the extension name against allowlist
    validated_name = validate_extension_name(extension_name)
    
    # Use psycopg2.sql module for safe SQL composition with identifier quoting
    from psycopg2 import sql
    
    if if_not_exists:
        query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
            sql.Identifier(validated_name)
        )
    else:
        query = sql.SQL("CREATE EXTENSION {}").format(
            sql.Identifier(validated_name)
        )
    
    cursor = connection.cursor()
    try:
        cursor.execute(query)
        connection.commit()
        print(f"Successfully installed extension: {validated_name}")
        return True
    except psycopg2.Error as e:
        connection.rollback()
        print(f"Error installing extension '{validated_name}': {e}")
        raise
    finally:
        cursor.close()


def list_installed_extensions(connection) -> list:
    """List all currently installed extensions."""
    cursor = connection.cursor()
    try:
        cursor.execute(
            "SELECT extname, extversion FROM pg_extension ORDER BY extname;"
        )
        extensions = cursor.fetchall()
        return extensions
    finally:
        cursor.close()


def uninstall_extension(connection, extension_name: str, cascade: bool = False) -> bool:
    """
    Safely uninstall a PostgreSQL extension.
    
    Uses allowlist validation and safe SQL composition.
    """
    validated_name = validate_extension_name(extension_name)
    
    from psycopg2 import sql
    
    if cascade:
        query = sql.SQL("DROP EXTENSION IF EXISTS {} CASCADE").format(
            sql.Identifier(validated_name)
        )
    else:
        query = sql.SQL("DROP EXTENSION IF EXISTS {}").format(
            sql.Identifier(validated_name)
        )
    
    cursor = connection.cursor()
    try:
        cursor.execute(query)
        connection.commit()
        print(f"Successfully uninstalled extension: {validated_name}")
        return True
    except psycopg2.Error as e:
        connection.rollback()
        print(f"Error uninstalling extension '{validated_name}': {e}")
        raise
    finally:
        cursor.close()


def get_db_connection(host: str, port: int, dbname: str, user: str, password: str):
    """Create a database connection with reasonable defaults."""
    return psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password,
        connect_timeout=10,
    )


